var sdk = window.sdk || {};
(function () {
  // Count Contacts
  this.calculateContacts = async function (executionContext) {
    const formContext = executionContext.getFormContext();
    let accountId = formContext.data.[[1]].getId().replace(/{|}/g, '');
    let count = 0;
    await Xrm.WebApi.retrieveMultipleRecords("Contact",
      `?$select=contactid&$filter=_parentaccountid_value eq ${accountId} and [[2]] eq 0`).then(
      function (result) {
        for (var i = 0; i < result.entities.length; i++) {
          count++;
        }
      },
      function (error) {
        console.log(error.message);
      }
    );
    formContext.getAttribute("new_NumberActiveContact").setValue(count);
  }
}).call(sdk);
